      clauses = []
      prev_subject = None
      for t in triples:
          # Strip surrounding quotes from object if present
          obj = t.object.strip('"')
          # Format numeric values with commas for readability
          if obj.replace(".", "", 1).isdigit():
              try:
                  num = float(obj)
                  # Preserve integer formatting when possible
                  if num.is_integer():
                      obj = f"{int(num):,}"
                  else:
                      obj = f"{num:,.2f}"
              except ValueError:
                  pass

          render = phrase_map.get(t.predicate)
          if render:
              clause = render(t.subject, obj)
          else:
              clause = f"{t.subject} {t.predicate} {obj}"

          # If the subject repeats, drop it for a smoother flow
          if prev_subject is not None and t.subject == prev_subject:
              # Remove leading subject and any following space/comma
